import pygame
import random
from typing import List, Tuple, Optional
from dataclasses import dataclass
from task0 import *

def new_tetromino() -> Tetromino:
    """Generates a new tetromino with a random shape and initial rotation/position."""
    shape_key = random.choice(list(TETROMINO_SHAPES.keys()))
    return Tetromino(
        shape_key=shape_key,
        rotation=0,
        position=(0, GRID_WIDTH // 2 - 2 if shape_key != "O" else GRID_WIDTH // 2 - 1),
        color=SHAPE_COLORS[shape_key]
    )

def valid_position(grid: List[List[Optional[Tuple[int, int, int]]]], tetromino: Tetromino) -> bool:
    """Checks if all blocks of the tetromino are within grid bounds and not occupied."""
    for row, col in tetromino.blocks:
        if row < 0 or row >= GRID_HEIGHT or col < 0 or col >= GRID_WIDTH or grid[row][col] is not None:
            return False
    return True

def move_tetromino(tetromino: Tetromino, direction: Tuple[int, int], grid: List[List[Optional[Tuple[int, int, int]]]]) -> Tetromino:
    """
    Attempts to move the tetromino by the given row and column offsets.
    Returns the new tetromino if the move is valid, otherwise returns the original.
    """
    dr, dc = direction
    new_tetromino = Tetromino(
        shape_key=tetromino.shape_key,
        rotation=tetromino.rotation,
        position=(tetromino.position[0] + dr, tetromino.position[1] + dc),
        color=tetromino.color
    )
    if valid_position(grid, new_tetromino):
        return new_tetromino
    else:
        return tetromino

def rotate_tetromino(tetromino: Tetromino, grid: List[List[Optional[Tuple[int, int, int]]]]) -> Tetromino:
    """
    Attempts to rotate the tetromino clockwise.
    Returns the new tetromino if the rotation is valid, otherwise returns the original.
    """
    new_rotation = (tetromino.rotation + 1) % len(TETROMINO_SHAPES[tetromino.shape_key])
    new_tetromino = Tetromino(
        shape_key=tetromino.shape_key,
        rotation=new_rotation,
        position=tetromino.position,
        color=tetromino.color
    )
    if valid_position(grid, new_tetromino):
        return new_tetromino
    else:
        return tetromino

def lock_tetromino(grid: List[List[Optional[Tuple[int, int, int]]]], tetromino: Tetromino) -> None:
    """Locks the tetromino into the grid, converting its blocks into colored gems."""
    for row, col in tetromino.blocks:
        grid[row][col] = tetromino.color

def check_tetris_clear(grid: List[List[Optional[Tuple[int, int, int]]]]) -> List[int]:
    """Checks for and returns a list of indices of completed rows to clear."""
    rows_to_clear = []
    for i, row in enumerate(grid):
        if all(cell is not None for cell in row):
            rows_to_clear.append(i)
    return rows_to_clear

def clear_rows(grid: List[List[Optional[Tuple[int, int, int]]]], rows_to_clear: List[int]) -> None:
    """Clears the specified rows from the grid and shifts the above rows down."""
    for row_index in sorted(rows_to_clear, reverse=True):
        del grid[row_index]
        grid.insert(0, [None] * GRID_WIDTH)

def check_match_3(grid: List[List[Optional[Tuple[int, int, int]]]]) -> List[Tuple[int, int]]:
    """
    Checks for horizontal and vertical match-3 gem formations.
    Returns a list of coordinates (row, col) of gems to be cleared.
    """
    matches = []

    # Check horizontal matches
    for row in range(GRID_HEIGHT):
        for col in range(GRID_WIDTH - 2):
            if (grid[row][col] is not None and
                grid[row][col] == grid[row][col+1] == grid[row][col+2]):
                matches.extend([(row, col), (row, col+1), (row, col+2)])

    # Check vertical matches
    for col in range(GRID_WIDTH):
        for row in range(GRID_HEIGHT - 2):
            if (grid[row][col] is not None and
                grid[row][col] == grid[row+1][col] == grid[row+2][col]):
                matches.extend([(row, col), (row+1, col), (row+2, col)])

    # Remove duplicate coordinates
    return list(set(matches))

def clear_matches(grid: List[List[Optional[Tuple[int, int, int]]]], matches: List[Tuple[int, int]]) -> None:
    """Clears the specified gem matches from the grid."""
    for row, col in matches:
        grid[row][col] = None

